/**
 * @fileoverview Tooltip barrel.
 * @module module/Tooltip
 */
import { default as razyui } from '../index.js';
import { TooltipDef as DEF } from './Tooltip.def.js';
import Tooltip from './Tooltip/index.js';

razyui.Tooltip = Tooltip;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Tooltip);
}

export default Tooltip;

export const stylesheet = null;
